local MatchFacts = {}print("loaded MATCH FACTS LUA")local FLOW_OFFLINE = "offline"local FLOW_FTF = "ftf"local bndHomeCrest = "bnd_home_team_crest"local bndAwayCrest = "bnd_away_team_crest"local bndHomeName = "bnd_home_team_name"local bndAwayName = "bnd_away_team_name"local bndResult = "bnd_result"local bndShootoutResult = "bnd_shootout_result"local bndMatchType = "bnd_match_type"local bndStadium = "bnd_stadium"local bndHomeUserData = "bnd_home_user_data"local bndAwayUserData = "bnd_away_user_data"local bndOfflineCrestsVisible = "bnd_offline_crests_visible"local bndOnlineUserPlatesVisible = "bnd_online_user_plates_visible"local flowlocal SIDE_HOME = "home"local SIDE_AWAY = "away"function MatchFacts:new(init)  print("New Function MatchFactsLua")  local o = init or {}  setmetatable(o, self)  self.__index = self  o.services = {    settingsService = o.api("SettingsService"),    gameSetup = o.api("GameSetupService"),    userPlate = o.api("UserPlateService"),    socialService = o.api("SocialService"),    matchInfo = o.api("MatchInfoService")  }  flow = o.data.flow  local matchTypeLabel = ""  if o.data.gamemode == "real" or o.data.type == nil then    matchTypeLabel = o.loc.LocalizeString("LTXT_SEA_REAL")  else    matchTypeLabel = o.loc.LocalizeString(string.format("%s_%s_%s", o.data.gamemode, o.data.flow, o.data.type))  end  o.TeamsData = o.services.matchInfo.GetMatchTeams()  o.ResultsData = ""  o.currentOptions = o.services.settingsService.GetCurrentOptions()  o.isValidFrame = false  o.im.Subscribe(bndMatchType, function()    o.im.Publish(bndMatchType, matchTypeLabel)  end  )  o.im.Subscribe(bndStadium, function()    o.im.Publish(bndStadium, o.currentOptions.stadium)  end  )  o.im.Subscribe(bndResult, function()    o:getResultsData()  end  )  o.im.Subscribe(bndShootoutResult, function()    o.im.Publish(bndShootoutResult, o:getShootoutResult())  end  )  o.im.Subscribe(bndOfflineCrestsVisible, function()    o.im.Publish(bndOfflineCrestsVisible, flow == FLOW_OFFLINE or flow == FLOW_FTF)  end  )  o.im.Subscribe(bndOnlineUserPlatesVisible, function()    o.im.Publish(bndOnlineUserPlatesVisible, flow ~= FLOW_OFFLINE and flow ~= FLOW_FTF)  end  )  if flow == FLOW_OFFLINE or flow == FLOW_FTF then    homeCrest = {      name = "$Crest",      id = o.TeamsData[1].assetId    }    awaycrest = {      name = "$Crest",      id = o.TeamsData[2].assetId    }    o.im.Subscribe(bndHomeCrest, function()      o.im.Publish(bndHomeCrest, homeCrest)    end    )    o.im.Subscribe(bndAwayCrest, function()      o.im.Publish(bndAwayCrest, awaycrest)    end    )    o.im.Subscribe(bndHomeName, function()      o.im.Publish(bndHomeName, o.TeamsData[1].teamName)    end    )    o.im.Subscribe(bndAwayName, function()      o.im.Publish(bndAwayName, o.TeamsData[2].teamName)    end    )  else    o.userSide = o.services.gameSetup.IsHostTeam() and SIDE_HOME or SIDE_AWAY    do      local homeName = ""      local awayName = ""      local homeImage = -1      local awayImage = -1      if o.userSide == SIDE_HOME then        homeImage = o.services.socialService.GetImagePathForUser(true)        awayImage = o.services.socialService.GetImagePathForOpponent(true)      else        homeImage = o.services.socialService.GetImagePathForOpponent(true)        awayImage = o.services.socialService.GetImagePathForUser(true)      end      o.im.Subscribe(bndHomeUserData, function()        o:setUserData(bndHomeUserData, homeImage, o.TeamsData[1].assetId)      end      )      o.im.Subscribe(bndAwayUserData, function()        o:setUserData(bndAwayUserData, awayImage, o.TeamsData[2].assetId)      end      )    end  end  return oendfunction MatchFacts:update(elapsedTime)  if self.isValidFrame == false then    self:getResultsData()  endendfunction MatchFacts:getResultsData()  self.ResultsData = self.services.matchInfo.GetMatchResult()  if self.ResultsData ~= nil then    self.im.Publish(bndResult, self.ResultsData)    self.isValidFrame = true  endendfunction MatchFacts:getShootoutResult()  local matchScore = self.services.matchInfo.GetMatchScore()  local homeScore = matchScore.homeShootout  local awayScore = matchScore.awayShootout  if homeScore == -1 or awayScore == -1 then    return ""  else    return string.format("(%s - %s) %s", tostring(homeScore), tostring(awayScore), self.loc.LocalizeString("LTXT_CMN_PENALTIES_ABBR"))  endendfunction MatchFacts:setUserData(binding, image, team)  local userData = {}  userData.userImage = image  userData.team = team  self.im.Publish(binding, userData)endfunction MatchFacts:finalize()  self.im.Unsubscribe(bndResult)  self.im.Unsubscribe(bndShootoutResult)  self.im.Unsubscribe(bndMatchType)  self.im.Unsubscribe(bndStadium)  self.im.Unsubscribe(bndOfflineCrestsVisible)  self.im.Unsubscribe(bndOnlineUserPlatesVisible)  if flow == FLOW_OFFLINE or flow == FLOW_FTF then    self.im.Unsubscribe(bndHomeCrest)    self.im.Unsubscribe(bndAwayCrest)    self.im.Unsubscribe(bndHomeName)    self.im.Unsubscribe(bndAwayName)  else    self.im.Unsubscribe(bndHomeUserData)    self.im.Unsubscribe(bndAwayUserData)  endendreturn MatchFacts